sp_widget.css:
.dtech-pad-right-header{
  padding-right:50px;
}

.dtech-task-header{
  background-color: #fff;
  border: 1px solid transparent;
  border-radius: 5px;
  box-shadow: 0 2px 2px rgba(0, 0, 0, .05);
  padding: 5px 15px;
  border-bottom: 1px solid transparent;
  border-top-right-radius: 3px;
  border-top-left-radius: 3px; 
  margin-top: 5px;
  margin-left: -8px;
  margin-right: -8px;  
}

.dtech-task-header-menu-row {
  align-items: start;
  column-gap: 5px;
  display: flex;
  flex-direction: row;
  flex-wrap: wrap;
}

.dtech-task-header-value {
    font-weight: 800;
    color: #000000;
}

.dtech-member-item-row {
	align-items: center;
	column-gap: 5px;
	display: flex;
	flex-direction: row;
	flex-wrap: nowrap;
}

.dtech-menu-item-divider {
	height: 1px;
	margin: 9px 0;
	overflow: hidden;
	background-color: #e5e5e5;
}

.dtech-stack-circle-wrapper {
  position: relative;
}

.dtech-stack-circle-0,
.dtech-stack-circle-1,
.dtech-stack-circle-2, 
.dtech-stack-circle-3,
.dtech-stack-circle-4,
.dtech-stack-circle-5 {
  position: absolute;
}

.dtech-stack-circle-0{
  left: 0px;
}
.dtech-stack-circle-1{
  left: 15px;
}
.dtech-stack-circle-2{
  left: 30px;
}
.dtech-stack-circle-3{
  left: 45px;
}
.dtech-stack-circle-4{
  left: 60px;
}
.dtech-stack-circle-5{
  left: 75px;
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
/* Special License Rights
*  The Government's rights to use, display, or disclose this software are restricted.
*  Any reproduction of computer software, computer software documentation,
*  or portions thereof marked with this legend must also reproduce the markings. */
// 2.8.5 | 2023-08-11 | raj  | STRY0136615 - STRETCH-PLACEHOLDER- Header UI Control
//                                      New Widget

(function($sp, input, data, options, gs) {
	var api_task = new api_tasker_task();

	main();

	function main(){
		data.table = (input || {}).table || (options || {}).table || $sp.getParameter("table") || "x_153465_discovert_route_task_instance";
		data.sys_id = (input || {}).sys_id || (options || {}).sys_id || $sp.getParameter("sys_id") || $sp.getParameter("sl_sys_id");
		data.query = "";
		data.view = (input || {}).view || (options || {}).view || $sp.getParameter("view") || $sp.getParameter("v");
		data.isModal = (input || {}).isModal || (options || {}).isModal || $sp.getParameter("isModal") || false;
		data.showLongDates = (input || {}).showLongDates || (options || {}).showLongDates || $sp.getParameter("showLongDates") || true;
		data.responseEditorControl = (input || {}).responseEditorControl || (options || {}).responseEditorControl || 'form';
		data.responseColumnStyle = 'iconsOnly';

		if(input && input.getActions==true){
			getTaskActions();
			return;
		}
		data.taskRecordObjectList = {};

		var taskTreeObjectKey = api_tasker_task.CONST_DTECH_TASK_TREE_OBJECT;
		data.taskTreeObjectKey = taskTreeObjectKey;
		data.taskTreeField = "u_task_tree";
		data.taskRecordObjectList[taskTreeObjectKey] = true;

		var operationalObjectKey = api_tasker_task.CONST_DTECH_OPERATIONAL_OBJECT;
		data.parentField = "parent";
		data.operationalObjectKey = operationalObjectKey;
		data.taskRecordObjectList[operationalObjectKey] = true;

		var subTasksObjectKey = api_tasker_task.CONST_DTECH_SUB_TASKS_OBJECT;
		data.subTasksObjectKey = subTasksObjectKey;
		data.taskRecordObjectList[subTasksObjectKey] = true;
		data.subtaskMaxRows = 5;

		var itemMembersObjectKey = api_tasker_task.CONST_DTECH_ITEM_MEMBERS_OBJECT;
		data.itemMembersObjectKey = itemMembersObjectKey;
		data.taskRecordObjectList[itemMembersObjectKey] = true;
		data.itemMembersMaxRows = undefined;

		var officeObjectKey = api_tasker_task.CONST_DTECH_OFFICE_OBJECT;
		data.officeObjectKey = officeObjectKey;
		data.taskRecordObjectList[officeObjectKey] = true;
		data.officeField = "primary_assignee";

		var durationObjectKey = api_tasker_task.CONST_DTECH_DURATION_OBJECT;
		data.durationObjectKey = durationObjectKey;
		data.taskRecordObjectList[durationObjectKey] = true;

		var stateObjectKey = api_tasker_task.CONST_DTECH_STATE_OBJECT;
		data.stateObjectKey = stateObjectKey;
		data.stateField = "state";
		data.taskRecordObjectList[stateObjectKey] = true;

		var responseObjectKey = api_tasker_task.CONST_DTECH_RESPONSE_OBJECT;
		data.responseObjectKey = responseObjectKey;
		data.taskRecordObjectList[responseObjectKey] = true;

		var taskerFilesObjectKey = api_tasker_task.CONST_DTECH_TASKER_FILES_OBJECT;
		data.taskerFilesObjectKey = taskerFilesObjectKey;
		data.taskRecordObjectList[taskerFilesObjectKey] = true;
		data.taskerFilesMaxRows = 5;

//    Actions are not loaded until user requests them to ensure state hasn't changed
//		var taskerContextMenuObjectKey = api_tasker_task.CONST_DTECH_TASK_CONTEXT_MENU_ACTIONS_OBJECT;
//		data.taskerContextMenuObjectKey = taskerContextMenuObjectKey;
//		data.taskRecordObjectList[taskerContextMenuObjectKey] = true;
		data.taskActions = {};

		data.taskRecordObj = api_task.getTaskRecordObjects(data.sys_id, data.taskRecordObjectList);

		//**************************************************************************************************
		// NOTE: if we move all header items into directives, then this section will move into the directive
		//**************************************************************************************************
		data.state_label = data.taskRecordObj[stateObjectKey][data.stateField].label;
		data.state_display_value = data.taskRecordObj[stateObjectKey][data.stateField].display_value;
		data.state_value = data.taskRecordObj[stateObjectKey][data.stateField].value;

		data.u_task_tree_label = data.taskRecordObj[taskTreeObjectKey][data.taskTreeField].label;
		data.u_task_tree_display_value = data.taskRecordObj[taskTreeObjectKey][data.taskTreeField].display_value;
		data.u_task_tree_value = data.taskRecordObj[taskTreeObjectKey][data.taskTreeField].value;
		//**************************************************************************************************
		// NOTE: if we move all header items into directives, then this section will move into the directive
		//**************************************************************************************************

// TODO - get the title into the directive
		data.title = "TODO - get the title into the directive";
		data.durationTitle = gs.getMessage('Tasker - Title - Duration Modal') + ': ' + data.title;
		data.assignmentTitle = gs.getMessage('Tasker - Title - Assignment Modal') + ': ' + data.title;
		data.operationalTitle = gs.getMessage('Tasker - Title - Operational Modal');
		data.taskerFilesTitle = gs.getMessage('Tasker - Title - Files Modal');

		function getTaskActions(){
			data.taskActions = api_task.getContextMenuInformation(data.sys_id);
		}
	}
})($sp, input, data, options, gs);
